```cpp
{
  const APInt *C;
  if (match(Src, m_LShr(m_APInt(C), m_Value(X))) && C->isPowerOf2()) {
    // trunc (C >> X) to i1 --> X == log2(C), where C is pow2
    return new ICmpInst(ICmpInst::Predicate::ICMP_EQ, X, 
                        ConstantInt::get(X->getType(), C->logBase2()));
  }
}
```

